content.problemStatement:
Alexandra has some distinct integer numbers **a1,a2...an**.
Count number of pairs **(i,j)** such that:


** 1≤ i ≤ n**** 1≤ j ≤ n**** ai &lt; aj**&nbsp;

code.C:
#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int arr[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        qsort(arr, N, sizeof(int), compare);
        long long count = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                if (arr[i] < arr[j]) {
                    count++;
                }
            }
        }
        printf("%lld\n", count);
    }
    return 0;
}

